# WRONG — pe is a Python attribute, stays on CPU
class BadPE(nn.Module):
    def __init__(self, d_model, max_len):
        super().__init__()
        self.pe = torch.zeros(1, max_len, d_model)   # ← plain tensor, not a buffer!

    def forward(self, x):
        return x + self.pe[:, :x.size(1)]            # RuntimeError on CUDA model


# CORRECT — register_buffer ensures pe moves with the model
class GoodPE(nn.Module):
    def __init__(self, d_model, max_len):
        super().__init__()
        pe = torch.zeros(1, max_len, d_model)
        # ... fill pe values ...
        self.register_buffer("pe", pe)               # moves with .to(device)

    def forward(self, x):
        return x + self.pe[:, :x.size(1)]

import math

# WRONG — missing scale, PE may dominate at initialization
def bad_embed(token_ids, embed, pe):
    x = embed(token_ids)          # norm ≈ 1 at init for standard initialization
    return pe(x)                  # PE values [−1, 1] are ~√d larger than embedding values


# CORRECT — scale embeddings before adding PE
def good_embed(token_ids, embed, pe, d_model):
    x = embed(token_ids) * math.sqrt(d_model)   # norm ≈ √d, matches PE magnitude
    return pe(x)

# WRONG — no length guard; IndexError on long inputs
class UnsafeLearnedPE(nn.Module):
    def __init__(self, d_model, max_seq_len=512):
        super().__init__()
        self.pe = nn.Embedding(max_seq_len, d_model)

    def forward(self, x):
        positions = torch.arange(x.size(1), device=x.device)
        return x + self.pe(positions)       # IndexError if x.size(1) > 512


# CORRECT — validate length and raise a descriptive error
class SafeLearnedPE(nn.Module):
    def __init__(self, d_model, max_seq_len=512):
        super().__init__()
        self.max_seq_len = max_seq_len
        self.pe = nn.Embedding(max_seq_len, d_model)

    def forward(self, x):
        L = x.size(1)
        if L > self.max_seq_len:
            raise ValueError(
                f"Input sequence length {L} exceeds max_seq_len {self.max_seq_len}. "
                f"Truncate the input or increase max_seq_len before creating the model."
            )
        positions = torch.arange(L, device=x.device)
        return x + self.pe(positions)
